import{z as e}from"zod";export const EmbeddingScopeSchema=e.enum(["project","character","chat"]),VectorDocumentSchema=e.object({id:e.number().int(),scope:EmbeddingScopeSchema,scopeId:e.string(),source:e.string(),content:e.string(),chunkIndex:e.number().int().default(0),metadata:e.record(e.string(),e.unknown()).default({}),createdAt:e.string().default("")}),EmbedderConfigSchema=e.object({type:e.enum(["stub","openai"]),model:e.string().default("text-embedding-3-small"),dimensions:e.number().int().positive().default(1536),apiKey:e.string().optional(),baseUrl:e.string().optional()}),RetrieverConfigSchema=e.object({topK:e.number().int().min(1).max(100).default(5),minScore:e.number().min(0).max(1).default(0),maxTokens:e.number().int().positive().default(2e3),hybrid:e.boolean().default(!1)});
